import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState } from 'react';
import type { ExamDetails, MatrixRow, Question } from './types';
import { generateQuestionsFromMatrix } from './services/geminiService';
import Step1ExamDetails from './components/Step1_ExamDetails';
import Step2ExamMatrix from './components/Step2_ExamMatrix';
import Step3GeneratedExam from './components/Step3_GeneratedExam';
import { initialMatrix } from './constants';
import { Header, Footer } from './components/Layout';

const App: React.FC = () => {
  const [step, setStep] = useState<number>(1);
  const [examDetails, setExamDetails] = useState<ExamDetails | null>(null);
  const [matrix, setMatrix] = useState<MatrixRow[]>(initialMatrix);
  const [generatedQuestions, setGeneratedQuestions] = useState<Question[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  const handleDetailsSubmit = (details: ExamDetails) => {
    setExamDetails(details);
    setStep(2);
  };

  const handleGenerateExam = async () => {
    if (!examDetails) return;
    setIsLoading(true);
    setError(null);
    try {
      const questions = await generateQuestionsFromMatrix(matrix, examDetails);
      setGeneratedQuestions(questions);
      setStep(3);
    } catch (err) {
      setError('Đã có lỗi xảy ra khi tạo câu hỏi. Vui lòng thử lại.');
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const restart = () => {
    setStep(1);
    setExamDetails(null);
    setMatrix(initialMatrix);
    setGeneratedQuestions([]);
    setError(null);
  }

  const renderStep = () => {
    switch (step) {
      case 1:
        return <Step1ExamDetails onSubmit={handleDetailsSubmit} />;
      case 2:
        return (
          <Step2ExamMatrix
            matrix={matrix}
            setMatrix={setMatrix}
            onGenerate={handleGenerateExam}
            isLoading={isLoading}
            onBack={() => setStep(1)}
            examDetails={examDetails!}
          />
        );
      case 3:
        return <Step3GeneratedExam questions={generatedQuestions} examDetails={examDetails!} onRestart={restart} />;
      default:
        return <Step1ExamDetails onSubmit={handleDetailsSubmit} />;
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 text-gray-800 flex flex-col">
      <Header />
      <main className="flex-grow container mx-auto px-4 py-8">
        {error && (
          <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded relative mb-4" role="alert">
            <strong className="font-bold">Lỗi!</strong>
            <span className="block sm:inline"> {error}</span>
          </div>
        )}
        {renderStep()}
      </main>
      <Footer />
    </div>
  );
};

export default App;

export enum CognitiveLevel {
  NHAN_BIET = 'Nhận biết',
  THONG_HIEU = 'Thông hiểu',
  VAN_DUNG = 'Vận dụng',
  VAN_DUNG_CAO = 'Vận dụng cao',
}

export enum QuestionType {
  MULTIPLE_CHOICE = 'Trắc nghiệm',
  ESSAY = 'Tự luận',
}

export interface ExamDetails {
  school: string;
  subject: string;
  grade: string;
  duration: number;
  examType: string;
}

export interface QuestionCount {
  mcq: number; // Multiple Choice Questions
  essay: number;
}

export interface MatrixRow {
  id: number;
  topic: string;
  [CognitiveLevel.NHAN_BIET]: QuestionCount;
  [CognitiveLevel.THONG_HIEU]: QuestionCount;
  [CognitiveLevel.VAN_DUNG]: QuestionCount;
  [CognitiveLevel.VAN_DUNG_CAO]: QuestionCount;
}

export interface Question {
  topic: string;
  cognitiveLevel: CognitiveLevel;
  questionText: string;
  questionType: 'multiple_choice' | 'essay';
  options?: string[];
  correctAnswer?: string;
  solution: string;
}

export interface GeminiQuestion {
    questionText: string;
    questionType: 'multiple_choice' | 'essay';
    options?: string[];
    correctAnswer?: string;
    solution: string;
}

import type { MatrixRow } from './types';
import { CognitiveLevel } from './types';

export const COGNITIVE_LEVELS: CognitiveLevel[] = [
  CognitiveLevel.NHAN_BIET,
  CognitiveLevel.THONG_HIEU,
  CognitiveLevel.VAN_DUNG,
  CognitiveLevel.VAN_DUNG_CAO,
];

export const initialMatrix: MatrixRow[] = [
  {
    id: 1,
    topic: 'Chủ đề 1: [Tên chủ đề]',
    [CognitiveLevel.NHAN_BIET]: { mcq: 2, essay: 0 },
    [CognitiveLevel.THONG_HIEU]: { mcq: 1, essay: 0 },
    [CognitiveLevel.VAN_DUNG]: { mcq: 0, essay: 1 },
    [CognitiveLevel.VAN_DUNG_CAO]: { mcq: 0, essay: 0 },
  },
  {
    id: 2,
    topic: 'Chủ đề 2: [Tên chủ đề]',
    [CognitiveLevel.NHAN_BIET]: { mcq: 1, essay: 0 },
    [CognitiveLevel.THONG_HIEU]: { mcq: 2, essay: 0 },
    [CognitiveLevel.VAN_DUNG]: { mcq: 1, essay: 0 },
    [CognitiveLevel.VAN_DUNG_CAO]: { mcq: 0, essay: 1 },
  },
];

export const MCQ_POINTS = 0.25;
export const ESSAY_POINTS_DEFAULT = 1.0;

import { GoogleGenAI, Type } from "@google/genai";
import type { MatrixRow, ExamDetails, Question, GeminiQuestion } from '../types';
import { CognitiveLevel, QuestionType } from '../types';

const API_KEY = process.env.API_KEY;

if (!API_KEY) {
  throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: API_KEY });

const questionGenerationSchema = {
    type: Type.ARRAY,
    items: {
        type: Type.OBJECT,
        properties: {
            questionText: { type: Type.STRING, description: "Nội dung đầy đủ của câu hỏi." },
            questionType: { type: Type.STRING, enum: ['multiple_choice', 'essay'], description: "Loại câu hỏi: trắc nghiệm (multiple_choice) hoặc tự luận (essay)." },
            options: { 
                type: Type.ARRAY, 
                items: { type: Type.STRING },
                description: "Mảng chứa 4 phương án A, B, C, D cho câu hỏi trắc nghiệm."
            },
            correctAnswer: { type: Type.STRING, description: "Đáp án đúng cho câu hỏi trắc nghiệm (A, B, C, hoặc D)." },
            solution: { type: Type.STRING, description: "Hướng dẫn giải chi tiết hoặc đáp án cho câu hỏi." }
        },
        required: ["questionText", "questionType", "solution"],
    }
};

const generateQuestionsForCell = async (
  topic: string,
  level: CognitiveLevel,
  type: QuestionType,
  count: number,
  details: ExamDetails
): Promise<Question[]> => {
  if (count === 0) return [];

  const questionTypeString = type === QuestionType.MULTIPLE_CHOICE ? 'trắc nghiệm' : 'tự luận';
  const formatInstruction = type === QuestionType.MULTIPLE_CHOICE
    ? "Đối với câu hỏi trắc nghiệm, phải có 4 phương án (A, B, C, D) và chỉ định rõ đáp án đúng."
    : "Đối với câu hỏi tự luận, đưa ra đề bài rõ ràng.";

  const prompt = `
    Hãy tạo ra ${count} câu hỏi ${questionTypeString} thuộc chủ đề "${topic}" dành cho học sinh lớp ${details.grade} môn ${details.subject}.
    Các câu hỏi phải ở mức độ nhận thức: "${level}".
    ${formatInstruction}
    Cung cấp hướng dẫn giải hoặc đáp án chi tiết cho mỗi câu hỏi.
    Bám sát chương trình giáo dục Việt Nam.
  `;

  try {
    const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: {
            responseMimeType: "application/json",
            responseSchema: questionGenerationSchema,
            temperature: 0.7,
        }
    });

    const generatedItems = JSON.parse(response.text) as GeminiQuestion[];

    return generatedItems.map(item => ({
      ...item,
      topic,
      cognitiveLevel: level,
    }));
  } catch (error) {
    console.error(`Error generating questions for ${topic} - ${level} - ${type}:`, error);
    // Return dummy data on failure to not block the whole process
    return Array(count).fill(null).map(() => ({
        topic,
        cognitiveLevel: level,
        questionText: `[Lỗi tạo câu hỏi cho chủ đề: ${topic}]`,
        questionType: type === QuestionType.MULTIPLE_CHOICE ? 'multiple_choice' : 'essay',
        solution: 'Vui lòng thử lại hoặc tự soạn câu hỏi này.'
    }));
  }
};

export const generateQuestionsFromMatrix = async (
  matrix: MatrixRow[],
  details: ExamDetails
): Promise<Question[]> => {
  const allPromises: Promise<Question[]>[] = [];

  for (const row of matrix) {
    for (const level of Object.values(CognitiveLevel)) {
      const { mcq, essay } = row[level];
      if (mcq > 0) {
        allPromises.push(generateQuestionsForCell(row.topic, level, QuestionType.MULTIPLE_CHOICE, mcq, details));
      }
      if (essay > 0) {
        allPromises.push(generateQuestionsForCell(row.topic, level, QuestionType.ESSAY, essay, details));
      }
    }
  }

  const results = await Promise.all(allPromises);
  return results.flat();
};

